#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2400005;
int n,id[N],tr[N],ls[N],rs[N],cnt,cnt2;
char trc[N];
void pushup(int u)
{
	tr[u]=tr[ls[u]]+tr[rs[u]];
}
int update(int u,int l,int r,char val)
{
//	cout<<"update "<<u<<" "<<l<<" "<<r<<" "<<val<<"\n";
//	cout<<u<<" "<<l<<" "<<r<<" "<<val<<'\n';
	tr[++cnt]=tr[u];
	trc[cnt]=trc[u];
	ls[cnt]=ls[u];
	rs[cnt]=rs[u];
//	dbg(ls[cnt]);
//	dbg(rs[cnt]);
//	cout<<" cnt:"<<cnt<<"\n";
	u=cnt;
	if(l==r)
	{
//		cout<<"l==r return cnt;\ntr["<<u<<"]=1\n";
		trc[u]=val;
		tr[u]=1;
		return u;
	}
	int mid=(l+r)/2;
	if(tr[ls[u]]==mid-l+1)
	{
//		cout<<"rrr----------------\n";
		rs[u]=update(rs[u],mid+1,r,val);
//		cout<"______________rrr\n";
//		dbg(rs[u]);
	}
	else
	{
//		cout<<"ls["<<u<<"]="<<ls[u]<<"  "<<tr[ls[u]]<<"\n";
//		cout<<"lll---------------------\n";
		ls[u]=update(ls[u],l,mid,val);
//		cout<<"________________lll\n";
//		dbg(ls[u]);
	}
	pushup(u);
	return u;
}
char query(int u,int l,int r,int num)
{
//	cout<<u<<" "<<l<<" "<<r<<" "<<num<<" ???\n";
	if((l>num)||(num>r)) return '#';
//	cout<<"YES ( l:"<<l<<" , r:"<<r<<" num:"<<num<<")\n";
	if(l==r)
	{
//		cout<<"l==r return "<<trc[u]<<"\n";
		return trc[u];
	}
//	cout<<"--------------\n";
	int mid=(l+r)/2;
	char ans=query(ls[u],l,mid,num);
//	cout<<"-----------------________________\n";
//	cout<<" ans("<<ans<<")\n";
	if(ans!='#') return ans;
//	cout<<"query :  -----------------------\n";
	int tmp=query(rs[u],mid+1,r,num);
//	cout<<"_______________________  "<<tmp<<"\n";
	return tmp;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		char op;
		cin>>op;
		if(op=='T')
		{
			char c;
			cin>>c;
			cnt2++;
			id[cnt2]=update(id[cnt2-1],1,n,c);
		}
		if(op=='U')
		{
			int x;
			cin>>x;
			cnt2++;
			id[cnt2]=id[cnt2-1-x];
		}
		if(op=='Q')
		{
			int x;
			cin>>x;
			cout<<query(id[cnt2],1,n,x)<<"\n";
		}
	}
	return 0;
}
